class Solution:
    def racecar(self, target: int) -> int:
        memo = {}
        def dfs(pos, speed):
            if (pos, speed) in memo:
                return memo[(pos, speed)]
            if pos == 0:
                return 1
            if speed > 0:
                res = dfs(pos - speed // 2, -speed) + 1
            else:
                res = dfs(pos + speed // 2, -speed) + 1
            memo[(pos, speed)] = res
            return res
        return dfs(0, 1)
